import pandas as pd, json
import numpy as np

base = "original/0f329774-cc0f-48fe-b5c1-393e3a80bc0a"

# Load data
payments = pd.read_csv(f"{base}/payments.csv")
with open(f"{base}/fees.json") as f:
    fees = json.load(f)

# Merchant parameters
account_type = "R"
mcc = 5942
capture_delay = "1"
monthly_volume_bucket = "100k-1m"
monthly_fraud_level = ">8.3%"

# Belles January fraudulent transactions
belles_jan = payments[
    (payments['merchant'] == 'Belles_cookbook_store') & 
    (payments['day_of_year'] >= 1) & 
    (payments['day_of_year'] <= 31)
]
fraud_txns = belles_jan[belles_jan['has_fraudulent_dispute'] == True].copy()

def specificity_score(rule):
    """Count how many non-null fields the rule has. More specific = more non-null fields."""
    score = 0
    if rule['account_type'] is not None and len(rule['account_type']) > 0:
        score += 1
    if rule['capture_delay'] is not None:
        score += 1
    if rule['monthly_fraud_level'] is not None:
        score += 1
    if rule['monthly_volume'] is not None:
        score += 1
    if rule['merchant_category_code'] is not None and len(rule['merchant_category_code']) > 0:
        score += 1
    if rule['is_credit'] is not None:
        score += 1
    if rule['aci'] is not None and len(rule['aci']) > 0:
        score += 1
    if rule['intracountry'] is not None:
        score += 1
    return score

def matches_rule(rule, card_scheme, is_credit, aci, intracountry):
    """Check if a fee rule matches the given transaction/merchant characteristics"""
    if rule['card_scheme'] != card_scheme:
        return False
    at = rule['account_type']
    if at is not None and len(at) > 0:
        if account_type not in at:
            return False
    if rule['capture_delay'] is not None:
        if rule['capture_delay'] != capture_delay:
            return False
    if rule['monthly_fraud_level'] is not None:
        if rule['monthly_fraud_level'] != monthly_fraud_level:
            return False
    if rule['monthly_volume'] is not None:
        if rule['monthly_volume'] != monthly_volume_bucket:
            return False
    mcc_list = rule['merchant_category_code']
    if mcc_list is not None and len(mcc_list) > 0:
        if mcc not in mcc_list:
            return False
    if rule['is_credit'] is not None:
        if rule['is_credit'] != is_credit:
            return False
    aci_list = rule['aci']
    if aci_list is not None and len(aci_list) > 0:
        if aci not in aci_list:
            return False
    if rule['intracountry'] is not None:
        if bool(rule['intracountry']) != intracountry:
            return False
    return True

all_aci = ['A', 'B', 'C', 'D', 'E', 'F', 'G']
results = {}

for target_aci in all_aci:
    total_fee = 0
    matched_count = 0
    unmatched_txns = []

    for idx, txn in fraud_txns.iterrows():
        card_scheme = txn['card_scheme']
        is_credit = txn['is_credit']
        intracountry = txn['issuing_country'] == txn['acquirer_country']
        txn_value = txn['eur_amount']

        matching_rules = [r for r in fees if matches_rule(r, card_scheme, is_credit, target_aci, intracountry)]

        if len(matching_rules) > 0:
            # Pick the most specific rule (highest specificity score)
            matching_rules.sort(key=lambda r: specificity_score(r), reverse=True)
            rule = matching_rules[0]
            fee = rule['fixed_amount'] + rule['rate'] * txn_value / 10000
            total_fee += fee
            matched_count += 1
        else:
            unmatched_txns.append({
                'card_scheme': card_scheme,
                'is_credit': is_credit,
                'intracountry': intracountry,
                'txn_value': txn_value
            })

    results[target_aci] = {
        'total_fee': total_fee,
        'matched_count': matched_count,
        'unmatched_count': len(unmatched_txns),
        'unmatched_samples': unmatched_txns[:5]
    }
    print(f"\n=== ACI {target_aci} ===")
    print(f"  Matched: {matched_count}/{len(fraud_txns)}")
    print(f"  Total Fee: {total_fee:.4f} EUR")
    if unmatched_txns:
        # Show which card_schemes are unmatched
        unmatched_schemes = set(t['card_scheme'] for t in unmatched_txns)
        print(f"  Unmatched card_schemes: {unmatched_schemes}")

# Summary
print("\n\n========== SUMMARY (sorted by total fee) ==========")
aci_desc = {
    'A': 'Card present - Non-authenticated',
    'B': 'Card Present - Authenticated',
    'C': 'Tokenized card with mobile device',
    'D': 'Card Not Present - Card On File',
    'E': 'Card Not Present - Recurring Bill Payment',
    'F': 'Card Not Present - 3-D Secure',
    'G': 'Card Not Present - Non-3-D Secure (CURRENT)'
}
for aci in sorted(results.keys(), key=lambda x: results[x]['total_fee']):
    r = results[aci]
    marker = " <-- CURRENT" if aci == 'G' else ""
    print(f"  ACI {aci}: {r['total_fee']:.4f} EUR (matched {r['matched_count']}/{len(fraud_txns)}) - {aci_desc[aci]}{marker}")

